@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800&display=swap');

@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  :root {
    --background: 210 20% 98%;
    --foreground: 215 25% 15%;

    --card: 0 0% 100%;
    --card-foreground: 215 25% 15%;

    --popover: 0 0% 100%;
    --popover-foreground: 215 25% 15%;

    --primary: 168 80% 36%;
    --primary-foreground: 0 0% 100%;

    --secondary: 210 18% 95%;
    --secondary-foreground: 215 25% 15%;

    --muted: 210 14% 93%;
    --muted-foreground: 215 10% 50%;

    --accent: 168 60% 94%;
    --accent-foreground: 168 80% 25%;

    --destructive: 0 72% 51%;
    --destructive-foreground: 0 0% 100%;

    --success: 142 72% 40%;
    --success-foreground: 0 0% 100%;

    --warning: 38 92% 50%;
    --warning-foreground: 0 0% 100%;

    --info: 210 90% 55%;
    --info-foreground: 0 0% 100%;

    --border: 214 20% 90%;
    --input: 214 20% 90%;
    --ring: 168 80% 36%;

    --radius: 0.75rem;

    --sidebar-background: 215 25% 15%;
    --sidebar-foreground: 210 14% 83%;
    --sidebar-primary: 168 80% 45%;
    --sidebar-primary-foreground: 0 0% 100%;
    --sidebar-accent: 215 20% 20%;
    --sidebar-accent-foreground: 210 14% 93%;
    --sidebar-border: 215 20% 22%;
    --sidebar-ring: 168 80% 45%;
    --sidebar-muted: 215 15% 35%;

    --gradient-primary: linear-gradient(135deg, hsl(168, 80%, 36%), hsl(190, 80%, 40%));
    --gradient-sidebar: linear-gradient(180deg, hsl(215, 28%, 12%), hsl(215, 25%, 18%));
    --shadow-card: 0 1px 3px 0 rgb(0 0 0 / 0.06), 0 1px 2px -1px rgb(0 0 0 / 0.06);
    --shadow-card-hover: 0 10px 25px -5px rgb(0 0 0 / 0.08), 0 8px 10px -6px rgb(0 0 0 / 0.04);
  }

  .dark {
    --background: 215 25% 10%;
    --foreground: 210 14% 93%;
    --card: 215 25% 13%;
    --card-foreground: 210 14% 93%;
    --popover: 215 25% 13%;
    --popover-foreground: 210 14% 93%;
    --primary: 168 80% 45%;
    --primary-foreground: 0 0% 100%;
    --secondary: 215 20% 18%;
    --secondary-foreground: 210 14% 93%;
    --muted: 215 20% 18%;
    --muted-foreground: 215 10% 55%;
    --accent: 168 60% 15%;
    --accent-foreground: 168 60% 70%;
    --destructive: 0 62.8% 30.6%;
    --destructive-foreground: 210 40% 98%;
    --border: 215 20% 22%;
    --input: 215 20% 22%;
    --ring: 168 80% 45%;
    --sidebar-background: 215 28% 8%;
    --sidebar-foreground: 210 14% 83%;
    --sidebar-primary: 168 80% 45%;
    --sidebar-primary-foreground: 0 0% 100%;
    --sidebar-accent: 215 20% 14%;
    --sidebar-accent-foreground: 210 14% 93%;
    --sidebar-border: 215 20% 15%;
    --sidebar-ring: 168 80% 45%;
  }
}

@layer base {
  * {
    @apply border-border;
  }
  body {
    @apply bg-background text-foreground font-sans antialiased;
    font-family: 'Inter', sans-serif;
  }
}

@layer utilities {
  .gradient-primary {
    background: var(--gradient-primary);
  }
  .gradient-sidebar {
    background: var(--gradient-sidebar);
  }
  .shadow-card {
    box-shadow: var(--shadow-card);
  }
  .shadow-card-hover {
    box-shadow: var(--shadow-card-hover);
  }
  .animate-fade-in {
    animation: fade-in 0.3s ease-in;
  }
  .animate-slide-in {
    animation: slide-in 0.3s ease-in;
  }
  @keyframes fade-in {
    from {
      opacity: 0;
    }
    to {
      opacity: 1;
    }
  }
  @keyframes slide-in {
    from {
      opacity: 0;
      transform: translateX(-10px);
    }
    to {
      opacity: 1;
      transform: translateX(0);
    }
  }
}

@layer components {
  .stat-card {
    @apply bg-card rounded-xl p-6 shadow-card transition-all duration-300 hover:shadow-card-hover hover:-translate-y-0.5 border border-border/50;
  }
  .page-header {
    @apply text-2xl font-bold tracking-tight text-foreground;
  }
  .table-container {
    @apply bg-card rounded-xl shadow-card border border-border/50 overflow-hidden;
  }
}

