    --sidebar-accent-foreground: 210 14% 93%;
    --sidebar-border: 215 20% 22%;
    --sidebar-ring: 168 80% 45%;
    --sidebar-muted: 215 15% 35%;

    --gradient-primary: linear-gradient(135deg, hsl(168, 80%, 36%), hsl(190, 80%, 40%));
    --gradient-sidebar: linear-gradient(180deg, hsl(215, 28%, 12%), hsl(215, 25%, 18%));
    --shadow-card: 0 1px 3px 0 rgb(0 0 0 / 0.06), 0 1px 2px -1px rgb(0 0 0 / 0.06);
    --shadow-card-hover: 0 10px 25px -5px rgb(0 0 0 / 0.08), 0 8px 10px -6px rgb(0 0 0 / 0.04);
  }

  .dark {
    --background: 215 25% 10%;
    --foreground: 210 14% 93%;
    --card: 215 25% 13%;
    --card-foreground: 210 14% 93%;
    --popover: 215 25% 13%;
    --popover-foreground: 210 14% 93%;
    --primary: 168 80% 45%;
    --primary-foreground: 0 0% 100%;
    --secondary: 215 20% 18%;
    --secondary-foreground: 210 14% 93%;
    --muted: 215 20% 18%;
    --muted-foreground: 215 10% 55%;
    --accent: 168 60% 15%;
    --accent-foreground: 168 60% 70%;
    --destructive: 0 62.8% 30.6%;
    --destructive-foreground: 210 40% 98%;
    --border: 215 20% 22%;
    --input: 215 20% 22%;
    --ring: 168 80% 45%;
    --sidebar-background: 215 28% 8%;
    --sidebar-foreground: 210 14% 83%;
    --sidebar-primary: 168 80% 45%;
    --sidebar-primary-foreground: 0 0% 100%;
    --sidebar-accent: 215 20% 14%;
    --sidebar-accent-foreground: 210 14% 93%;
    --sidebar-border: 215 20% 15%;
    --sidebar-ring: 168 80% 45%;
  }
}

@layer base {
  * {
    @apply border-border;
  }
  body {
    @apply bg-background text-foreground font-sans antialiased;
    font-family: 'Inter', sans-serif;
  }
}

@layer utilities {
  .gradient-primary {
    background: var(--gradient-primary);
  }
  .gradient-sidebar {
    background: var(--gradient-sidebar);
  }
  .shadow-card {
    box-shadow: var(--shadow-card);
  }
  .shadow-card-hover {
    box-shadow: var(--shadow-card-hover);
  }
  .animate-fade-in {
    animation: fade-in 0.3s ease-in;
  }
  .animate-slide-in {
    animation: slide-in 0.3s ease-in;
  }
  @keyframes fade-in {
    from {
      opacity: 0;
    }
    to {
      opacity: 1;
    }
  }
  @keyframes slide-in {
    from {
      opacity: 0;
      transform: translateX(-10px);
    }
    to {
      opacity: 1;
      transform: translateX(0);
    }
  }
}

@layer components {
  .stat-card {
    @apply bg-card rounded-xl p-6 shadow-card transition-all duration-300 hover:shadow-card-hover hover:-translate-y-0.5 border border-border/50;
  }
  .page-header {
    @apply text-2xl font-bold tracking-tight text-foreground;
  }
  .table-container {
    @apply bg-card rounded-xl shadow-card border border-border/50 overflow-x-auto;
  }
}

export type AppRole = "simple_utilisateur" | "responsable" | "administrateur";

export const normalizeRole = (role?: string | null): AppRole | null => {
  if (!role) return null;

  // Accept legacy formats such as ROLE_ADMINISTRATEUR, "simple utilisateur", or "admin".
  const cleaned = role.trim().toLowerCase().replace(/[\s-]+/g, "_");
  const normalized = cleaned.startsWith("role_") ? cleaned.slice(5) : cleaned;

  if (normalized === "simple_utilisateur" || normalized === "simpleutilisateur" || normalized === "simple") {
    return "simple_utilisateur";
  }
  if (normalized === "responsable") {
    return "responsable";
  }
  if (normalized === "administrateur" || normalized === "admin") {
    return "administrateur";
  }

  return null;
};

export const canAccessRole = (allowedRoles: AppRole[], role?: string | null) => {
  const normalizedRole = normalizeRole(role);
  return normalizedRole ? allowedRoles.includes(normalizedRole) : false;
};

export const getDefaultRoute = (role?: string | null) => {
  const normalizedRole = normalizeRole(role);
  if (normalizedRole === "simple_utilisateur") {
    return "/formations";
  }
  if (normalizedRole === "responsable" || normalizedRole === "administrateur") {
    return "/dashboard";
  }
  return "/login";
};

import { useEffect, useMemo, useState } from "react";
import { GraduationCap, Users, UserCheck, DollarSign, TrendingUp, BarChart3, Building2, CalendarDays, Clock3 } from "lucide-react";
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  PieChart,
  Pie,
  Legend,
  LineChart,
  Line,
} from "recharts";
import StatCard from "@/components/shared/StatCard";
import API from "@/services/api";
import { Formation, Formateur, Participant, Planning } from "@/types";

interface DomaineStat {
  domaineId: number | null;
  domaine: string;
  count: number;
  budgetTotal: number;
}

interface StructureStat {
  structureId: number | null;
  structure: string;
  count: number;
}

interface AnneeStat {
  annee: number;
  count: number;
  budgetTotal: number;
}

interface StatistiquesResponse {
  totalFormations: number;
  totalParticipants: number;
  totalBudget?: number;
  budgetMoyen?: number;
  formationsParDomaine?: DomaineStat[];
  participantsParStructure?: StructureStat[];
  formationsParAnnee?: AnneeStat[];
}

const formatMoney = (value: number) => `${new Intl.NumberFormat("fr-FR").format(Math.round(value))} DT`;
const formatCompactMoney = (value: number) => `${(value / 1000).toFixed(1)}k DT`;

const parseLocalDate = (value?: string | null) => {
  if (!value) return null;
  const parsed = new Date(`${value}T00:00:00`);
  return Number.isNaN(parsed.getTime()) ? null : parsed;
};

const formatMonthLabel = (date: Date) =>
  date.toLocaleDateString("fr-FR", {
    month: "short",
    year: "numeric",
  });

const normalizePlanningStatus = (status?: string | null) => {
  const normalized = (status ?? "en_attente").trim().toLowerCase().replace(/[\s-]+/g, "_");

  if (normalized.includes("annul")) return "Annulé";
  if (normalized.includes("termin") || normalized.includes("realis")) return "Terminé";
  if (normalized.includes("cours")) return "En cours";
  if (normalized.includes("planif") || normalized.includes("prev")) return "Planifié";
  if (normalized.includes("brouillon") || normalized.includes("draft")) return "Brouillon";

  return status?.trim() ? status.trim() : "Sans statut";
};

const DASHBOARD_COLORS = [
  "#0ea5a4",
  "#3b82f6",
  "#22c55e",
  "#f59e0b",
  "#a855f7",
  "#ef4444",
  "#14b8a6",
  "#6366f1",
];

const Dashboard = () => {
  const [formations, setFormations] = useState<Formation[]>([]);
  const [formateurs, setFormateurs] = useState<Formateur[]>([]);
  const [participants, setParticipants] = useState<Participant[]>([]);
  const [plannings, setPlannings] = useState<Planning[]>([]);
  const [stats, setStats] = useState<StatistiquesResponse | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const loadData = async () => {
      try {
        const [formationsRes, formateursRes, participantsRes, planningsRes, statsRes] = await Promise.allSettled([
          API.get("/formations"),
          API.get("/formateurs"),
          API.get("/participants"),
          API.get("/planning"),
          API.get("/statistiques"),
        ]);

        setFormations(formationsRes.status === "fulfilled" ? formationsRes.value.data || [] : []);
        setFormateurs(formateursRes.status === "fulfilled" ? formateursRes.value.data || [] : []);
        setParticipants(participantsRes.status === "fulfilled" ? participantsRes.value.data || [] : []);
        setPlannings(planningsRes.status === "fulfilled" ? planningsRes.value.data || [] : []);
        setStats(statsRes.status === "fulfilled" ? statsRes.value.data || null : null);
      } catch (error) {
        console.error("Erreur dashboard:", error);
      } finally {
        setIsLoading(false);
      }
    };

    loadData();
  }, []);

  const totalBudget = stats?.totalBudget ?? formations.reduce((sum, f) => sum + (f.budget ?? 0), 0);
  const budgetMoyen = stats?.budgetMoyen ?? (formations.length ? totalBudget / formations.length : 0);

  const formationsParAnnee = useMemo(() => {
    if (stats?.formationsParAnnee?.length) {
      return [...stats.formationsParAnnee]
        .sort((a, b) => a.annee - b.annee)
        .map((s) => ({ annee: String(s.annee), count: s.count, budget: s.budgetTotal ?? 0 }));
    }

    const grouped = formations.reduce<Record<number, { count: number; budget: number }>>((acc, current) => {
      const year = current.annee;
      if (!acc[year]) acc[year] = { count: 0, budget: 0 };
      acc[year].count += 1;
      acc[year].budget += current.budget ?? 0;
      return acc;
    }, {});

    return Object.entries(grouped)
      .sort(([a], [b]) => Number(a) - Number(b))
      .map(([annee, value]) => ({ annee, count: value.count, budget: value.budget }));
  }, [formations, stats]);

  const formationsParDomaine = useMemo(() => {
    const source = stats?.formationsParDomaine?.length
      ? stats.formationsParDomaine.map((s) => ({ name: s.domaine, count: s.count, budget: s.budgetTotal }))
      : (() => {
          const grouped = new Map<string, { count: number; budget: number }>();
          formations.forEach((formation) => {
            const name = formation.domaine?.libelle ?? "Sans domaine";
            const current = grouped.get(name) ?? { count: 0, budget: 0 };
            grouped.set(name, {
              count: current.count + 1,
              budget: current.budget + (formation.budget ?? 0),
            });
          });
          return Array.from(grouped.entries()).map(([name, value]) => ({ name, count: value.count, budget: value.budget }));
        })();

    return source
      .sort((a, b) => b.count - a.count)
      .map((item, index) => ({ ...item, color: DASHBOARD_COLORS[index % DASHBOARD_COLORS.length] }));
  }, [formations, stats]);

  const participantsParStructure = useMemo(() => {
    if (stats?.participantsParStructure?.length) {
      return [...stats.participantsParStructure]
        .map((s) => ({ structure: s.structure, count: s.count }))
        .sort((a, b) => b.count - a.count);
    }

    const grouped = new Map<string, number>();
    participants.forEach((participant) => {
      const key = participant.structure?.libelle ?? "Sans structure";
      grouped.set(key, (grouped.get(key) ?? 0) + 1);
    });

    return Array.from(grouped.entries())
      .map(([structure, count]) => ({ structure, count }))
      .sort((a, b) => b.count - a.count);
  }, [participants, stats]);

  const topDomaines = formationsParDomaine.slice(0, 6).map((item, index) => ({
    ...item,
    fill: item.color ?? DASHBOARD_COLORS[index % DASHBOARD_COLORS.length],
  }));
  const topStructures = participantsParStructure.slice(0, 8);

  const planningInsights = useMemo(() => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    const groupedByStatus = new Map<string, number>();
    const groupedByFormateur = new Map<string, number>();
    const groupedByMonth = new Map<string, number>();

    let totalParticipantsAffectes = 0;
    let totalDureeJours = 0;
    let planningsAvecParticipants = 0;
    let planningsAvenir = 0;
    let planningsEnCours = 0;

    plannings.forEach((planning) => {
      const startDate = parseLocalDate(planning.dateDebut);
      const endDate = parseLocalDate(planning.dateFin) ?? startDate;
      const labelStatus = normalizePlanningStatus(planning.status);
      const formateur = planning.formateurNom?.trim() || "Sans formateur";
      const participantCount = planning.participantIds?.length ?? 0;
      const durationDays = startDate && endDate ? Math.max(1, Math.round((endDate.getTime() - startDate.getTime()) / (1000 * 60 * 60 * 24)) + 1) : 0;

      groupedByStatus.set(labelStatus, (groupedByStatus.get(labelStatus) ?? 0) + 1);
      groupedByFormateur.set(formateur, (groupedByFormateur.get(formateur) ?? 0) + 1);

      if (startDate) {
        const monthKey = `${startDate.getFullYear()}-${String(startDate.getMonth() + 1).padStart(2, "0")}`;
        groupedByMonth.set(monthKey, (groupedByMonth.get(monthKey) ?? 0) + 1);

        if (startDate >= today) {
          planningsAvenir += 1;
        }
      }

      if (participantCount > 0) {
        planningsAvecParticipants += 1;
      }

      if (startDate && endDate && startDate <= today && endDate >= today) {
        planningsEnCours += 1;
      }

      totalParticipantsAffectes += participantCount;
      totalDureeJours += durationDays;
    });

    return {
      total: plannings.length,
      planningsAvenir,
      planningsEnCours,
      tauxAffectation: plannings.length > 0 ? Math.round((planningsAvecParticipants / plannings.length) * 100) : 0,
      participantsMoyens: plannings.length > 0 ? totalParticipantsAffectes / plannings.length : 0,
      tauxRemplissageMoyen:
        plannings.length > 0 && participants.length > 0
          ? Math.min(100, Math.round((totalParticipantsAffectes / (plannings.length * participants.length)) * 100))
          : 0,
      dureeMoyenne: plannings.length > 0 ? totalDureeJours / plannings.length : 0,
      formateursMobilises: groupedByFormateur.size,
      parStatut: Array.from(groupedByStatus.entries()).map(([name, count]) => ({ name, count })),
      parFormateur: Array.from(groupedByFormateur.entries())
        .map(([name, count]) => ({ name, count }))
        .sort((a, b) => b.count - a.count)
        .slice(0, 6),
      parMois: Array.from(groupedByMonth.entries())
        .sort(([a], [b]) => a.localeCompare(b))
        .map(([month, count]) => {
          const [year, monthNumber] = month.split("-").map(Number);
          const date = new Date(year, monthNumber - 1, 1);
          return { month: formatMonthLabel(date), count };
        }),
    };
  }, [participants.length, plannings]);

  if (isLoading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <p className="text-muted-foreground">Chargement des données...</p>
      </div>
    );
  }

  return (
    <div className="space-y-8">
      <div>
        <h1 className="page-header">Tableau de bord</h1>
        <p className="text-muted-foreground text-sm mt-1">
          Vue d&apos;ensemble des activités de formation — Excellent Training
        </p>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-5">
        <StatCard title="Formations" value={stats?.totalFormations ?? formations.length} icon={GraduationCap} color="primary" />
        <StatCard title="Participants" value={stats?.totalParticipants ?? participants.length} icon={Users} color="info" />
        <StatCard title="Formateurs" value={formateurs.length} icon={UserCheck} color="success" />
        <StatCard title="Budget Total" value={formatCompactMoney(totalBudget)} icon={DollarSign} color="warning" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="stat-card">
          <div className="flex items-center justify-between mb-2">
            <h3 className="font-semibold text-foreground">Budget moyen par formation</h3>
            <DollarSign className="w-5 h-5 text-warning" />
          </div>
          <p className="text-2xl font-bold text-foreground">{formatMoney(budgetMoyen)}</p>
          <p className="text-sm text-muted-foreground mt-1">Indicateur de pilotage financier global.</p>
        </div>

        <div className="stat-card">
          <div className="flex items-center justify-between mb-2">
            <h3 className="font-semibold text-foreground">Concentration formation / domaine</h3>
            <TrendingUp className="w-5 h-5 text-primary" />
          </div>
          {topDomaines.length === 0 ? (
            <p className="text-sm text-muted-foreground">Aucune donnée disponible.</p>
          ) : (
            <p className="text-2xl font-bold text-foreground">
              {topDomaines[0].name} ({topDomaines[0].count})
            </p>
          )}
          <p className="text-sm text-muted-foreground mt-1">Domaine le plus actif sur la période.</p>
        </div>
      </div>

      {/* Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Bar chart */}
        <div className="stat-card">
          <div className="flex items-center gap-2 mb-6">
            <BarChart3 className="w-5 h-5 text-primary" />
            <h3 className="font-semibold text-foreground">Formations par année</h3>
          </div>
          <ResponsiveContainer width="100%" height={280}>
            <BarChart data={formationsParAnnee}>
              <CartesianGrid strokeDasharray="3 3" stroke="hsl(214, 20%, 90%)" />
              <XAxis dataKey="annee" tick={{ fontSize: 12 }} />
              <YAxis allowDecimals={false} tick={{ fontSize: 12 }} />
              <Tooltip
                formatter={(value: number, name) => [name === "budget" ? formatMoney(value) : value, name === "budget" ? "Budget" : "Formations"]}
                contentStyle={{
                  borderRadius: "12px",
                  border: "1px solid hsl(214, 20%, 90%)",
                  boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
                }}
              />
              <Bar dataKey="count" name="Formations" fill="hsl(168, 80%, 36%)" radius={[6, 6, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>

        {/* Pie chart */}
        <div className="stat-card">
          <div className="flex items-center gap-2 mb-6">
            <TrendingUp className="w-5 h-5 text-primary" />
            <h3 className="font-semibold text-foreground">Répartition par domaine</h3>
          </div>
          {topDomaines.length === 0 ? (
            <p className="text-sm text-muted-foreground">Aucune donnée disponible.</p>
          ) : (
            <ResponsiveContainer width="100%" height={280}>
              <PieChart>
                <Pie
                  data={topDomaines}
                  cx="50%"
                  cy="50%"
                  innerRadius={58}
                  outerRadius={100}
                  paddingAngle={4}
                  dataKey="count"
                  nameKey="name"
                >
                </Pie>
                <Legend />
                <Tooltip
                  formatter={(value: number, name, payload) => {
                    if (name === "count") return [value, "Formations"];
                    return [formatMoney((payload?.payload as { budget?: number })?.budget ?? 0), "Budget"];
                  }}
                  contentStyle={{
                    borderRadius: "12px",
                    border: "1px solid hsl(214, 20%, 90%)",
                    boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
                  }}
                />
              </PieChart>
            </ResponsiveContainer>
          )}
        </div>
      </div>

      {/* New advanced charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="stat-card">
          <div className="flex items-center gap-2 mb-4">
            <Building2 className="w-5 h-5 text-primary" />
            <h3 className="font-semibold text-foreground">Suivi avancé par structure</h3>
          </div>
          {topStructures.length === 0 ? (
            <p className="text-sm text-muted-foreground">Aucune donnée disponible.</p>
          ) : (
            <ResponsiveContainer width="100%" height={280}>
              <BarChart data={topStructures} layout="vertical" margin={{ left: 10, right: 20 }}>
                <CartesianGrid strokeDasharray="3 3" stroke="hsl(214, 20%, 90%)" />
                <XAxis type="number" allowDecimals={false} tick={{ fontSize: 12 }} />
                <YAxis dataKey="structure" type="category" width={140} tick={{ fontSize: 12 }} />
                <Tooltip
                  formatter={(value: number) => [value, "Participants"]}
                  contentStyle={{
                    borderRadius: "12px",
                    border: "1px solid hsl(214, 20%, 90%)",
                    boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
                  }}
                />
                <Bar dataKey="count" fill="hsl(142, 72%, 40%)" radius={[0, 6, 6, 0]} />
              </BarChart>
            </ResponsiveContainer>
          )}
        </div>

        <div className="stat-card">
          <div className="flex items-center gap-2 mb-6">
            <TrendingUp className="w-5 h-5 text-primary" />
            <h3 className="font-semibold text-foreground">Budget par domaine</h3>
          </div>
          {topDomaines.length === 0 ? (
            <p className="text-sm text-muted-foreground">Aucune donnée disponible.</p>
          ) : (
            <ResponsiveContainer width="100%" height={280}>
              <BarChart data={topDomaines} layout="vertical" margin={{ left: 10, right: 20 }}>
                <CartesianGrid strokeDasharray="3 3" stroke="hsl(214, 20%, 90%)" />
                <XAxis type="number" tick={{ fontSize: 12 }} />
                <YAxis dataKey="name" type="category" width={140} tick={{ fontSize: 12 }} />
                <Tooltip
                  formatter={(value: number) => [formatMoney(value), "Budget"]}
                  contentStyle={{
                    borderRadius: "12px",
                    border: "1px solid hsl(214, 20%, 90%)",
                    boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
                  }}
                />
                <Bar dataKey="budget" fill="hsl(210, 90%, 55%)" radius={[0, 6, 6, 0]} />
              </BarChart>
            </ResponsiveContainer>
          )}
        </div>
      </div>

      {/* Statistiques avancées planning */}
      <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 gap-5">
        <StatCard title="Plannings" value={planningInsights.total} icon={CalendarDays} color="primary" />
        <StatCard title="Plannings à venir" value={planningInsights.planningsAvenir} icon={TrendingUp} color="success" />
        <StatCard title="En cours" value={planningInsights.planningsEnCours} icon={Clock3} color="warning" />
        <StatCard title="Participants/planning" value={planningInsights.participantsMoyens.toFixed(1)} icon={Users} color="info" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="stat-card">
          <div className="flex items-center gap-2 mb-6">
            <BarChart3 className="w-5 h-5 text-primary" />
            <h3 className="font-semibold text-foreground">Intensité formations (année)</h3>
          </div>
          {planningInsights.parMois.length === 0 ? (
            <p className="text-sm text-muted-foreground">Aucune donnée disponible.</p>
          ) : (
            <div className="space-y-3">
              <div className="grid grid-cols-6 gap-2">
                {(() => {
                  const mois = [
                    "Jan", "Fév", "Mar", "Avr",
                    "Mai", "Juin", "Juil", "Août",
                    "Sept", "Oct", "Nov", "Déc"
                  ];
                  const countByMonth = new Map(planningInsights.parMois.map((m) => {
                    const monthIndex = ["Jan", "Fév", "Mar", "Avr", "Mai", "Juin", "Juil", "Août", "Sept", "Oct", "Nov", "Déc"].findIndex((mo) =>
                      m.month.toLowerCase().includes(mo.toLowerCase())
                    );
                    return [monthIndex >= 0 ? monthIndex : -1, m.count];
                  }));
                  const maxCount = Math.max(...planningInsights.parMois.map((m) => m.count), 1);
                  return mois.map((mo, idx) => {
                    const count = countByMonth.get(idx) ?? 0;
                    const intensity = count / maxCount;
                    const hue = intensity > 0 ? Math.round(120 - intensity * 60) : 0;
                    const saturation = intensity > 0 ? 70 : 0;
                    const lightness = intensity > 0 ? 100 - intensity * 40 : 95;
                    return (
                      <div
                        key={mo}
                        className="rounded-lg p-3 text-center cursor-pointer transition hover:shadow-md"
                        style={{
                          backgroundColor: `hsl(${hue}, ${saturation}%, ${lightness}%)`,
                          border: "1px solid hsl(214, 20%, 90%)",
                        }}
                        title={`${mo}: ${count} formations`}
                      >
                        <p className="text-xs font-semibold">{mo}</p>
                        <p className="text-sm font-bold">{count}</p>
                      </div>
                    );
                  });
                })()}
              </div>
              <div className="flex items-center gap-2 text-xs text-muted-foreground mt-4">
                <div className="w-6 h-6 rounded" style={{ backgroundColor: "hsl(120, 70%, 60%)" }}></div>
                <span>Intensité élevée</span>
                <div className="w-6 h-6 rounded ml-4" style={{ backgroundColor: "hsl(60, 70%, 80%)" }}></div>
                <span>Intensité basse</span>
              </div>
            </div>
          )}
        </div>

        <div className="stat-card">
          <div className="flex items-center gap-2 mb-6">
            <UserCheck className="w-5 h-5 text-primary" />
            <h3 className="font-semibold text-foreground">Charge des formateurs</h3>
          </div>
          {planningInsights.parFormateur.length === 0 ? (
            <p className="text-sm text-muted-foreground">Aucune donnée disponible.</p>
          ) : (
            <ResponsiveContainer width="100%" height={280}>
              <BarChart data={planningInsights.parFormateur} layout="vertical" margin={{ left: 12, right: 16 }}>
                <CartesianGrid strokeDasharray="3 3" stroke="hsl(214, 20%, 90%)" />
                <XAxis type="number" allowDecimals={false} tick={{ fontSize: 12 }} />
                <YAxis dataKey="name" type="category" width={150} tick={{ fontSize: 12 }} />
                <Tooltip
                  formatter={(value: number) => [value, "Plannings"]}
                  contentStyle={{
                    borderRadius: "12px",
                    border: "1px solid hsl(214, 20%, 90%)",
                    boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
                  }}
                />
                <Bar dataKey="count" fill="hsl(168, 80%, 36%)" radius={[0, 6, 6, 0]} />
              </BarChart>
            </ResponsiveContainer>
          )}
        </div>

        <div className="stat-card">
          <div className="flex items-center gap-2 mb-6">
            <BarChart3 className="w-5 h-5 text-primary" />
            <h3 className="font-semibold text-foreground">Évolution mensuelle des plannings</h3>
          </div>
          {planningInsights.parMois.length === 0 ? (
            <p className="text-sm text-muted-foreground">Aucune donnée disponible.</p>
          ) : (
            <ResponsiveContainer width="100%" height={280}>
              <LineChart data={planningInsights.parMois}>
                <CartesianGrid strokeDasharray="3 3" stroke="hsl(214, 20%, 90%)" />
                <XAxis dataKey="month" tick={{ fontSize: 12 }} />
                <YAxis allowDecimals={false} tick={{ fontSize: 12 }} />
                <Tooltip
                  formatter={(value: number) => [value, "Plannings"]}
                  contentStyle={{
                    borderRadius: "12px",
                    border: "1px solid hsl(214, 20%, 90%)",
                    boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
                  }}
                />
                <Line type="monotone" dataKey="count" stroke="hsl(210, 90%, 55%)" strokeWidth={3} dot={{ r: 4 }} />
              </LineChart>
            </ResponsiveContainer>
          )}
        </div>
      </div>

      <div className="stat-card">
        <div className="flex items-center justify-between gap-4 mb-2">
          <Building2 className="w-5 h-5 text-primary" />
        </div>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mt-4">
          <div className="rounded-xl border border-border/60 bg-muted/30 p-4">
            <p className="text-xs uppercase tracking-wide text-muted-foreground">Durée moyenne</p>
            <p className="text-xl font-bold mt-1">{planningInsights.dureeMoyenne.toFixed(1)} jours</p>
          </div>
          <div className="rounded-xl border border-border/60 bg-muted/30 p-4">
            <p className="text-xs uppercase tracking-wide text-muted-foreground">Taux d’affectation</p>
            <p className="text-xl font-bold mt-1">{planningInsights.tauxAffectation}%</p>
          </div>
          <div className="rounded-xl border border-border/60 bg-muted/30 p-4">
            <p className="text-xs uppercase tracking-wide text-muted-foreground">Formateurs mobilisés</p>
            <p className="text-xl font-bold mt-1">{planningInsights.formateursMobilises}</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import { useEffect, useState } from "react";
import DataTable from "@/components/shared/DataTable";
import API from "@/services/api";
import { Domaine } from "@/types";
import { useToast } from "@/hooks/use-toast";

const DomainesPage = () => {
  const [domaines, setDomaines] = useState<Domaine[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const { toast } = useToast();

  useEffect(() => {
    loadDomaines();
  }, []);

  const loadDomaines = async () => {
    setIsLoading(true);
    try {
      const res = await API.get("/domaines");
      setDomaines(res.data || []);
    } catch (error) {
      console.error("Erreur:", error);
      toast({ title: "Erreur", description: "Impossible de charger les domaines" });
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (domaine: Domaine) => {
    if (window.confirm("Êtes-vous sûr de vouloir supprimer ce domaine ?")) {
      try {
        await API.delete(`/domaines/${domaine.id}`);
        toast({ title: "Succès", description: "Domaine supprimé" });
        loadDomaines();
      } catch (error) {
        console.error("Erreur:", error);
        toast({ title: "Erreur", description: "Impossible de supprimer le domaine" });
      }
    }
  };

  const columns = [
    { key: "id", label: "ID" },
    { key: "libelle", label: "Libellé" },
  ];

  return (
    <DataTable<Domaine>
      title="Domaines"
      description="Gérer les domaines de formation"
      columns={columns}
      data={domaines}
      searchKey="libelle"
      searchPlaceholder="Rechercher un domaine..."
      isLoading={isLoading}
      onAdd={() => toast({ title: "Ajouter un domaine", description: "Fonctionnalité à venir" })}
      onEdit={() => toast({ title: "Modifier", description: "Fonctionnalité à venir" })}
      onDelete={handleDelete}
    />
  );
};

export default DomainesPage;

import { useEffect, useState } from "react";
import DataTable from "@/components/shared/DataTable";
import CrudFormModal from "@/components/shared/CrudFormModal";
import API from "@/services/api";
import { Domaine } from "@/types";
import { useToast } from "@/hooks/use-toast";

const DomainesPage = () => {
  const [domaines, setDomaines] = useState<Domaine[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingDomaine, setEditingDomaine] = useState<Domaine | null>(null);
  const [libelle, setLibelle] = useState("");
  const [formError, setFormError] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { toast } = useToast();

  const notify = (title: string, description: string) =>
    toast({ id: Date.now().toString(), title, description });

  useEffect(() => {
    loadDomaines();
  }, []);

  const loadDomaines = async () => {
    setIsLoading(true);
    try {
      const res = await API.get("/domaines");
      setDomaines(res.data || []);
    } catch (error) {
      console.error("Erreur:", error);
      notify("Erreur", "Impossible de charger les domaines");
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (domaine: Domaine) => {
    try {
      await API.delete(`/domaines/${domaine.id}`);
      notify("Succès", "Domaine supprimé");
      loadDomaines();
    } catch (error) {
      console.error("Erreur:", error);
      notify("Erreur", "Impossible de supprimer le domaine");
    }
  };

  const openAddModal = () => {
    setEditingDomaine(null);
    setLibelle("");
    setFormError("");
    setIsModalOpen(true);
  };

  const openEditModal = (domaine: Domaine) => {
    setEditingDomaine(domaine);
    setLibelle(domaine.libelle);
    setFormError("");
    setIsModalOpen(true);
  };

  const handleSubmit = async () => {
    const value = libelle.trim();
    if (!value) {
      setFormError("Le libellé est obligatoire");
      return;
    }

    setIsSubmitting(true);
    setFormError("");
    try {
      if (editingDomaine) {
        await API.put(`/domaines/${editingDomaine.id}`, { id: editingDomaine.id, libelle: value });
        notify("Succès", "Domaine modifié");
      } else {
        await API.post("/domaines", { libelle: value });
        notify("Succès", "Domaine ajouté");
      }
      setIsModalOpen(false);
      loadDomaines();
    } catch (error) {
      console.error("Erreur:", error);
      setFormError(editingDomaine ? "Impossible de modifier le domaine" : "Impossible d'ajouter le domaine");
    } finally {
      setIsSubmitting(false);
    }
  };

  const columns = [
    { key: "id", label: "ID" },
    { key: "libelle", label: "Libellé" },
  ];

  return (
    <>
      <DataTable<Domaine>
        title="Domaines"
        description="Gérer les domaines de formation"
        columns={columns}
        data={domaines}
        searchKey="libelle"
        searchPlaceholder="Rechercher un domaine..."
        isLoading={isLoading}
        onAdd={openAddModal}
        onEdit={openEditModal}
        onDelete={handleDelete}
      />
      <CrudFormModal
        open={isModalOpen}
        title={editingDomaine ? "Modifier un domaine" : "Ajouter un domaine"}
        fields={[{ key: "libelle", label: "Libellé", required: true, placeholder: "Ex: Informatique" }]}
        values={{ libelle }}
        error={formError}
        isSubmitting={isSubmitting}
        submitLabel={editingDomaine ? "Modifier" : "Ajouter"}
        onChange={(_, value) => setLibelle(value)}
        onClose={() => setIsModalOpen(false)}
        onSubmit={handleSubmit}
      />
    </>
  );
};

