export default FormationsPage;

import { useEffect, useState } from "react";
import DataTable from "@/components/shared/DataTable";
import CrudFormModal from "@/components/shared/CrudFormModal";
import API from "@/services/api";
import { Formation, Domaine, Formateur, PlanningConflictResponse } from "@/types";
import { Badge } from "@/components/ui/badge";
import { useToast } from "@/hooks/use-toast";
import { useAuth } from "@/context/AuthContext";
import { canAccessRole } from "@/lib/rbac";

const FormationsPage = () => {
  const [formations, setFormations] = useState<Formation[]>([]);
  const [domaines, setDomaines] = useState<Domaine[]>([]);
  const [formateurs, setFormateurs] = useState<Formateur[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingFormation, setEditingFormation] = useState<Formation | null>(null);
  const [formValues, setFormValues] = useState<Record<string, string>>({
    titre: "",
    nom: "",
    description: "",
    annee: "2026",
    duree: "1",
    budget: "0",
    dateFormation: "",
    lieu: "",
    domaineId: "",
    formateurId: "",
  });
  const [formError, setFormError] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { toast } = useToast();
  const { userRole } = useAuth();
  const canManageFormations = canAccessRole(["responsable", "administrateur"], userRole);

  const notify = (title: string, description: string) =>
    toast({ id: Date.now().toString(), title, description });

  useEffect(() => {
    loadFormations();
    loadLookups();
  }, []);

  const loadLookups = async () => {
    if (!canManageFormations) {
      setDomaines([]);
      setFormateurs([]);
      return;
    }
    try {
      const [domainesRes, formateursRes] = await Promise.all([API.get("/domaines"), API.get("/formateurs")]);
      setDomaines(domainesRes.data || []);
      setFormateurs(formateursRes.data || []);
    } catch (error) {
      console.error("Erreur:", error);
    }
  };

  const loadFormations = async () => {
    setIsLoading(true);
    try {
      const res = await API.get("/formations");
      setFormations(res.data || []);
    } catch (error) {
      console.error("Erreur:", error);
      notify("Erreur", "Impossible de charger les formations");
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (formation: Formation) => {
    try {
      await API.delete(`/formations/${formation.id}`);
      notify("Succès", "Formation supprimée");
      loadFormations();
    } catch (error) {
      console.error("Erreur:", error);
      notify("Erreur", "Impossible de supprimer la formation");
    }
  };

  const openAddModal = () => {
    setEditingFormation(null);
    setFormValues({
      titre: "",
      nom: "",
      description: "",
      annee: "2026",
      duree: "1",
      budget: "0",
      dateFormation: "",
      lieu: "",
      domaineId: "",
      formateurId: "",
    });
    setFormError("");
    setIsModalOpen(true);
  };

  const openEditModal = (formation: Formation) => {
    setEditingFormation(formation);
    setFormValues({
      titre: formation.titre ?? "",
      nom: formation.nom ?? "",
      description: formation.description ?? "",
      annee: String(formation.annee ?? 2026),
      duree: String(formation.duree ?? 1),
      budget: String(formation.budget ?? 0),
      dateFormation: formation.dateFormation ?? "",
      lieu: formation.lieu ?? "",
      domaineId: formation.domaine?.id ? String(formation.domaine.id) : "",
      formateurId: formation.formateur?.id ? String(formation.formateur.id) : "",
    });
    setFormError("");
    setIsModalOpen(true);
  };

  const handleSubmit = async () => {
    const titre = formValues.titre.trim();
    const nom = formValues.nom.trim();
    const description = formValues.description.trim();
    const annee = Number(formValues.annee);
    const duree = Number(formValues.duree);
    const budget = Number(formValues.budget);
    const dateFormation = formValues.dateFormation.trim();
    const lieu = formValues.lieu.trim();
    const domaineId = formValues.domaineId ? Number(formValues.domaineId) : undefined;
    const formateurId = formValues.formateurId ? Number(formValues.formateurId) : undefined;

    if (!titre || !nom || !description || !dateFormation || !lieu) {
      setFormError("Titre, nom, description, date et lieu sont obligatoires");
      return;
    }
    if (!Number.isInteger(annee) || annee < 2000) {
      setFormError("Année invalide");
      return;
    }
    if (!Number.isInteger(duree) || duree < 1) {
      setFormError("Durée invalide");
      return;
    }
    if (Number.isNaN(budget) || budget < 0) {
      setFormError("Budget invalide");
      return;
    }

    setIsSubmitting(true);
    setFormError("");
    try {
      const payload = {
        id: editingFormation?.id,
        titre,
        nom,
        description,
        annee,
        duree,
        budget,
        dateFormation,
        lieu,
        domaine: domaineId ? { id: domaineId } : null,
        formateur: formateurId ? { id: formateurId } : null,
      };

      if (editingFormation) {
        await API.put(`/formations/${editingFormation.id}`, payload);
        notify("Succès", "Formation modifiée");
      } else {
        await API.post("/formations", payload);
        notify("Succès", "Formation ajoutée");
      }

      setIsModalOpen(false);
      loadFormations();
    } catch (error) {
      console.error("Erreur:", error);
      const apiError = error as { response?: { status?: number; data?: PlanningConflictResponse } };
      if (apiError.response?.status === 409 && apiError.response.data?.conflicts?.length) {
        const details = apiError.response.data.conflicts
          .map((c) => `- ${c.type}: ${c.details}${c.participantNom ? ` (${c.participantNom})` : ""}`)
          .join("\n");
        setFormError(`Conflits de planification:\n${details}`);
      } else {
        setFormError(editingFormation ? "Impossible de modifier la formation" : "Impossible d'ajouter la formation");
      }
    } finally {
      setIsSubmitting(false);
    }
  };

  const columns = [
    { key: "id", label: "ID" },
    { key: "titre", label: "Titre" },
    { key: "nom", label: "Nom" },
    {
      key: "description",
      label: "Description",
      render: (f: Formation) => <span className="max-w-xs whitespace-normal break-words block">{f.description}</span>,
    },
    { key: "dateFormation", label: "Date", render: (f: Formation) => f.dateFormation || "—" },
    { key: "lieu", label: "Lieu", render: (f: Formation) => f.lieu || "—" },
    {
      key: "domaineId",
      label: "Domaine ID",
      render: (f: Formation) => f.domaine?.id ?? "—",
    },
    {
      key: "domaine",
      label: "Domaine",
      render: (f: Formation) =>
        f.domaine ? (
          <Badge variant="secondary" className="font-normal">
            #{f.domaine.id} - {f.domaine.libelle}
          </Badge>
        ) : (
          "—"
        ),
    },
    { key: "annee", label: "Année" },
    { key: "duree", label: "Durée (j)" },
    {
      key: "budget",
      label: "Budget",
      render: (f: Formation) => `${f.budget.toLocaleString()} DT`,
    },
    {
      key: "formateurId",
      label: "Formateur ID",
      render: (f: Formation) => f.formateur?.id ?? "—",
    },
    {
      key: "formateur",
      label: "Formateur",
      render: (f: Formation) =>
        f.formateur ? (
          <Badge variant="outline" className="font-normal">
            #{f.formateur.id} - {f.formateur.prenom} {f.formateur.nom}
          </Badge>
        ) : (
          "—"
        ),
    },
    {
      key: "participants",
      label: "Participants",
      render: (f: Formation) => <Badge variant="outline">{f.participants?.length ?? "—"}</Badge>,
    },
  ];

  return (
    <>
      <DataTable<Formation>
        title="Formations"
        description="Gérer les formations organisées par le centre"
        columns={columns}
        data={formations}
        searchKey="titre"
        searchPlaceholder="Rechercher une formation..."
        isLoading={isLoading}
        onAdd={canManageFormations ? openAddModal : undefined}
        onEdit={canManageFormations ? openEditModal : undefined}
        onDelete={canManageFormations ? handleDelete : undefined}
      />
      <CrudFormModal
        open={isModalOpen}
        title={editingFormation ? "Modifier une formation" : "Ajouter une formation"}
        fields={[
          { key: "titre", label: "Titre", required: true },
          { key: "nom", label: "Nom", required: true },
          { key: "description", label: "Description", type: "textarea", required: true },
          { key: "annee", label: "Année", type: "number", required: true },
          { key: "duree", label: "Durée (jours)", type: "number", required: true },
          { key: "budget", label: "Budget", type: "number", required: true },
          { key: "dateFormation", label: "Date formation", type: "date", required: true },
          { key: "lieu", label: "Lieu", required: true },
          {
            key: "domaineId",
            label: "Domaine",
            type: "select",
            options: domaines.map((d) => ({ value: String(d.id), label: `#${d.id} - ${d.libelle}` })),
          },
          {
            key: "formateurId",
            label: "Formateur",
            type: "select",
            options: formateurs.map((f) => ({ value: String(f.id), label: `#${f.id} - ${f.prenom} ${f.nom}` })),
          },
        ]}
        values={formValues}
        error={formError}
        isSubmitting={isSubmitting}
        submitLabel={editingFormation ? "Modifier" : "Ajouter"}
        onChange={(key, value) => setFormValues((prev) => ({ ...prev, [key]: value }))}
        onClose={() => setIsModalOpen(false)}
        onSubmit={handleSubmit}
      />
    </>
  );
};

export default FormationsPage;

