package com.gestion.formation.service;

import com.gestion.formation.dto.PlanningConflictItemDTO;
import com.gestion.formation.dto.PlanningEventDTO;
import com.gestion.formation.entity.Formation;
import com.gestion.formation.entity.Formateur;
import com.gestion.formation.entity.Participant;
import com.gestion.formation.entity.Planning;
import com.gestion.formation.exception.PlanningConflictException;
import com.gestion.formation.repository.FormationRepository;
import com.gestion.formation.repository.ParticipantRepository;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.LocalDate;
import java.util.ArrayList;
import java.util.Collections;
import java.util.Comparator;
import java.util.HashMap;
import java.util.HashSet;
import java.util.List;
import java.util.Map;
import java.util.Objects;
import java.util.Set;
import java.util.stream.Collectors;

@Service
public class FormationService {

    @Autowired
    private FormationRepository formationRepository;

    @Autowired
    private ParticipantRepository participantRepository;

    @Autowired
    private PlanningEmailNotificationService planningEmailNotificationService;

    @Transactional(readOnly = true)
    public List<Formation> findAll() {
        return formationRepository.findAll();
    }

    @Transactional(readOnly = true)
    public Formation findById(Long id) {
        return formationRepository.findById(id)
                .orElseThrow(() -> new RuntimeException("Formation non trouvée"));
    }

    @Transactional
    public Formation save(Formation f) {
        validatePlanningConflicts(f, null);
        Formation saved = formationRepository.save(f);
        notifyPlanningByFormation(saved, false);
        return formationRepository.findById(saved.getId()).orElse(saved);
    }

    @Transactional
    public Formation update(Long id, Formation f) {
        f.setId(id);
        validatePlanningConflicts(f, id);
        Formation saved = formationRepository.save(f);
        notifyPlanningByFormation(saved, true);
        return formationRepository.findById(saved.getId()).orElse(saved);
    }

    @Transactional
    public void delete(Long id) {
        formationRepository.deleteById(id);
    }

    @Transactional(readOnly = true)
    public List<Formation> findByAnnee(Integer annee) {
        return formationRepository.findByAnnee(annee);
    }

    @Transactional(readOnly = true)
    public List<Participant> getParticipantsByFormation(Long formationId) {
        if (!formationRepository.existsById(formationId)) {
            throw new RuntimeException("Formation non trouvée");
        }
        return participantRepository.findByFormationId(formationId);
    }

    @Transactional
    public List<Participant> assignParticipants(Long formationId, List<Integer> participantIds) {
        Formation formation = findById(formationId);
        List<Integer> sanitizedIds = participantIds == null
                ? Collections.emptyList()
                : participantIds.stream().filter(Objects::nonNull).distinct().toList();

        List<Participant> participants = participantRepository.findAllById(sanitizedIds);
        if (participants.size() != sanitizedIds.size()) {
            throw new RuntimeException("Un ou plusieurs participants sont introuvables");
        }

        validateParticipantConflicts(formation, sanitizedIds, formationId);
        formation.setParticipants(participants);
        Formation saved = formationRepository.save(formation);
        notifyPlanningByFormation(saved, true);
        return participantRepository.findByFormationId(formationId);
    }

    @Transactional
    public List<Participant> addParticipant(Long formationId, Integer participantId) {
        List<Participant> existing = participantRepository.findByFormationId(formationId);
        Set<Integer> ids = existing.stream().map(Participant::getId).collect(Collectors.toCollection(HashSet::new));
        ids.add(participantId);
        List<Participant> updated = assignParticipants(formationId, new ArrayList<>(ids));
        return updated;
    }

    @Transactional
    public List<Participant> removeParticipant(Long formationId, Integer participantId) {
        List<Participant> existing = participantRepository.findByFormationId(formationId);
        List<Integer> ids = existing.stream()
                .map(Participant::getId)
                .filter(id -> !id.equals(participantId))
                .toList();
        List<Participant> updated = assignParticipants(formationId, ids);
        return updated;
    }

    @Transactional(readOnly = true)
    public List<PlanningEventDTO> getPlanning(LocalDate from, LocalDate to) {
        return formationRepository.findAll().stream()
                .filter(f -> f.getDateFormation() != null && f.getDuree() != null)
                .map(this::toPlanningEvent)
                .filter(event -> inRange(event.getStartDate(), event.getEndDate(), from, to))
                .sorted(Comparator.comparing(PlanningEventDTO::getStartDate))
                .toList();
    }

    private PlanningEventDTO toPlanningEvent(Formation f) {
        LocalDate start = f.getDateFormation();
        LocalDate end = computeEndDate(start, f.getDuree());
        Formateur formateur = f.getFormateur();
        String formateurNom = formateur == null ? null : formateur.getPrenom() + " " + formateur.getNom();

        return new PlanningEventDTO(
                f.getId(),
                f.getTitre(),
                start,
                end,
                f.getLieu(),
                formateur == null ? null : formateur.getId(),
                formateurNom,
                participantRepository.findByFormationId(f.getId()).size()
        );
    }

    private boolean inRange(LocalDate start, LocalDate end, LocalDate from, LocalDate to) {
        if (start == null || end == null) {
            return false;
        }
        if (from == null && to == null) {
            return true;
        }
        LocalDate effectiveFrom = from == null ? LocalDate.MIN : from;
        LocalDate effectiveTo = to == null ? LocalDate.MAX : to;
        return !start.isAfter(effectiveTo) && !end.isBefore(effectiveFrom);
    }

    private void validatePlanningConflicts(Formation formation, Long excludedFormationId) {
        LocalDate dateFormation = formation.getDateFormation();
        Integer duree = formation.getDuree();
        if (dateFormation == null || duree == null || duree < 1) {
            return;
        }

        LocalDate endDate = computeEndDate(dateFormation, duree);
        List<PlanningConflictItemDTO> conflicts = new ArrayList<>();

        Integer formateurId = formation.getFormateur() == null ? null : formation.getFormateur().getId();
        if (formateurId != null) {
            List<Formation> sameTrainer = excludedFormationId == null
                    ? formationRepository.findByFormateur_Id(formateurId)
                    : formationRepository.findByFormateur_IdAndIdNot(formateurId, excludedFormationId);
            sameTrainer.stream()
                    .filter(existing -> overlaps(dateFormation, endDate, existing.getDateFormation(), computeEndDate(existing.getDateFormation(), existing.getDuree())))
                    .forEach(existing -> conflicts.add(new PlanningConflictItemDTO(
                            "FORMATEUR_OCCUPE",
                            existing.getId(),
                            existing.getTitre(),
                            null,
                            null,
                            "Le formateur est deja planifie sur une autre formation."
                    )));
        }

        String lieu = formation.getLieu();
        if (lieu != null && !lieu.trim().isEmpty()) {
            List<Formation> sameLocation = excludedFormationId == null
                    ? formationRepository.findByLieuIgnoreCase(lieu.trim())
                    : formationRepository.findByLieuIgnoreCaseAndIdNot(lieu.trim(), excludedFormationId);
            sameLocation.stream()
                    .filter(existing -> overlaps(dateFormation, endDate, existing.getDateFormation(), computeEndDate(existing.getDateFormation(), existing.getDuree())))
                    .forEach(existing -> conflicts.add(new PlanningConflictItemDTO(
                            "LIEU_OCCUPE",
                            existing.getId(),
                            existing.getTitre(),
                            null,
                            null,
                            "Le lieu est deja reserve sur cette periode."
                    )));
        }

        List<Integer> participantIds = extractParticipantIds(formation.getParticipants());
        conflicts.addAll(findParticipantConflicts(participantIds, dateFormation, endDate, excludedFormationId));

        if (!conflicts.isEmpty()) {
            throw new PlanningConflictException("Conflits de planification detectes", deduplicateConflicts(conflicts));
        }
    }

    private void validateParticipantConflicts(Formation formation, List<Integer> participantIds, Long excludedFormationId) {
        LocalDate dateFormation = formation.getDateFormation();
        LocalDate endDate = computeEndDate(formation.getDateFormation(), formation.getDuree());
        if (dateFormation == null || endDate == null || participantIds == null || participantIds.isEmpty()) {
            return;
        }

        List<PlanningConflictItemDTO> conflicts = findParticipantConflicts(participantIds, dateFormation, endDate, excludedFormationId);
        if (!conflicts.isEmpty()) {
            throw new PlanningConflictException("Conflit participants detecte", deduplicateConflicts(conflicts));
        }
    }

    private List<PlanningConflictItemDTO> findParticipantConflicts(List<Integer> participantIds, LocalDate startDate, LocalDate endDate, Long excludedFormationId) {
        if (participantIds == null || participantIds.isEmpty()) {
            return Collections.emptyList();
        }

        List<Formation> candidateFormations = formationRepository.findByParticipantIdsForConflict(participantIds, excludedFormationId);
        Map<Integer, String> participantNames = participantRepository.findAllById(participantIds).stream()
                .collect(Collectors.toMap(Participant::getId, p -> p.getPrenom() + " " + p.getNom()));

        List<PlanningConflictItemDTO> conflicts = new ArrayList<>();
        for (Formation existing : candidateFormations) {
            LocalDate existingStart = existing.getDateFormation();
            LocalDate existingEnd = computeEndDate(existingStart, existing.getDuree());
            if (!overlaps(startDate, endDate, existingStart, existingEnd)) {
                continue;
            }
            List<Participant> existingParticipants = participantRepository.findByFormationId(existing.getId());
            for (Participant participant : existingParticipants) {
                if (!participantIds.contains(participant.getId())) {
                    continue;
                }
                conflicts.add(new PlanningConflictItemDTO(
                        "PARTICIPANT_OCCUPE",
                        existing.getId(),
                        existing.getTitre(),
                        participant.getId(),
                        participantNames.getOrDefault(participant.getId(), participant.getPrenom() + " " + participant.getNom()),
                        "Participant deja affecte sur une formation qui se chevauche."
                ));
            }
        }
        return conflicts;
    }

    private List<PlanningConflictItemDTO> deduplicateConflicts(List<PlanningConflictItemDTO> conflicts) {
        Map<String, PlanningConflictItemDTO> dedup = new HashMap<>();
        for (PlanningConflictItemDTO item : conflicts) {
            String key = item.getType() + "|" + item.getFormationId() + "|" + item.getParticipantId();
            dedup.putIfAbsent(key, item);
        }
        return new ArrayList<>(dedup.values());
    }

    private List<Integer> extractParticipantIds(List<Participant> participants) {
        if (participants == null || participants.isEmpty()) {
            return Collections.emptyList();
        }
        return participants.stream()
                .map(Participant::getId)
                .filter(Objects::nonNull)
                .distinct()
                .toList();
    }

    private LocalDate computeEndDate(LocalDate start, Integer duree) {
        if (start == null || duree == null || duree < 1) {
            return null;
        }
        return start.plusDays((long) duree - 1);
    }

    private boolean overlaps(LocalDate startA, LocalDate endA, LocalDate startB, LocalDate endB) {
        if (startA == null || endA == null || startB == null || endB == null) {
            return false;
        }
        return !startA.isAfter(endB) && !startB.isAfter(endA);
    }

    private void notifyPlanningByFormation(Formation formation, boolean updateEvent) {
        if (formation == null || formation.getDateFormation() == null || formation.getDuree() == null) {
            return;
        }
        Planning planning = new Planning();
        planning.setId(formation.getId());
        planning.setFormation(formation);
        planning.setDateDebut(formation.getDateFormation());
        planning.setDateFin(computeEndDate(formation.getDateFormation(), formation.getDuree()));
        planning.setLieu(formation.getLieu());
        planning.setFormateur(formation.getFormateur());
        planning.setParticipants(formation.getParticipants() != null ? formation.getParticipants() : participantRepository.findByFormationId(formation.getId()));

        planningEmailNotificationService.notifyParticipants(planning, planning.getParticipants(), updateEvent);
    }
}

